export const Sun: React.FC<SunProps> = ({ onSelect, isSelected, isPaused, simulationSpeed }) => {
  const meshRef = useRef<Mesh>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  const textureUrl = useMemo(() => generatePlanetTexture(SUN_DATA), []);
  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  // Generate Corona Glow Texture
  const glowUrl = useMemo(() => generateSunGlowTexture(), []);
  const glowTexture = useMemo(() => new TextureLoader().load(glowUrl), [glowUrl]);

  useFrame((state, delta) => {
    if (meshRef.current && !isPaused) {
      // Rotate the sun slowly
      meshRef.current.rotation.y += delta * 0.02 * simulationSpeed;
    }
  });

  return (
    <group>
      {/* Main Sun Body - Use dynamic size */}
      <mesh 
        ref={meshRef}
        onPointerDown={(e) => {
          e.stopPropagation();
          clickStartRef.current = { x: e.clientX, y: e.clientY };
        }}
        onClick={(e) => {
          e.stopPropagation();
          // Calculate distance moved
          const dx = e.clientX - clickStartRef.current.x;
          const dy = e.clientY - clickStartRef.current.y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          // Only trigger select if moved less than 5 pixels (click, not drag)
          if (distance < 5) {
            onSelect(SUN_DATA.id);
          }
        }}
        onPointerOver={() => {
          document.body.style.cursor = 'pointer';
          setHovered(true);
        }}
        onPointerOut={() => {
          document.body.style.cursor = 'auto';
          setHovered(false);
        }}
      >
        <sphereGeometry args={[SUN_DATA.size, 64, 64]} />
        <meshBasicMaterial 
          map={texture}
          // Set to white so the vivid texture colors show through properly
          color="#FFFFFF"
        />

        {/* Tech Style Hover Label */}
        {hovered && (
          <Html position={[0, SUN_DATA.size + 2.5, 0]} center zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
             <TechLabel name={SUN_DATA.name} color="#FF8C00" size={SUN_DATA.size} />
          </Html>
        )}
      </mesh>

      {/* Inner Glow Layer - Intense Gold/Orange */}
      <Billboard>
         <mesh position={[0, 0, -0.1]}>
            <planeGeometry args={[SUN_DATA.size * 2.8, SUN_DATA.size * 2.8]} />
            <meshBasicMaterial 
              map={glowTexture} 
              transparent 
              opacity={0.8} 
              depthWrite={false} 
              blending={2} // Additive
              color="#FFC400"
            />
         </mesh>
      </Billboard>

      {/* Outer Glow Layer (Large Halo) - Deep Red/Orange Corona */}
       <Billboard>
         <mesh position={[0, 0, -0.2]}>
            <planeGeometry args={[SUN_DATA.size * 5.0, SUN_DATA.size * 5.0]} />
            <meshBasicMaterial 
              map={glowTexture} 
              transparent 
              opacity={0.5} 
              depthWrite={false} 
              blending={2} // Additive
              color="#FF4500"
            />
         </mesh>
       </Billboard>
    </group>
  );
};

