  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
  togglePluto: () => void;
  isGestureMode: boolean;
  toggleGestureMode: () => void;
  showOrbits: boolean;
  toggleOrbits: () => void;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({ 
  selectedPlanet, 
  onClose,
  isPaused,
  togglePause,
  simulationSpeed,
  setSimulationSpeed,
  isStarshipActive,
