import React, { useRef, useMemo, useState } from 'react';
import { useFrame, extend } from '@react-three/fiber';
import { Mesh, Color, ShaderMaterial, Vector3, AdditiveBlending, TextureLoader } from 'three';
import { Billboard, Html, shaderMaterial } from '@react-three/drei';
import { generateSunGlowTexture } from '../utils/textureGenerator';
import { SUN_DATA } from '../constants';

interface SunProps {
  onSelect: (id: string) => void;
  isSelected: boolean;
  isPaused: boolean;
  simulationSpeed: number;
}

// --- Custom GLSL Shader for Dynamic Plasma Sun ---
// This simulates the Granulation (convection cells) and Limb Darkening seen in NASA SDO images.
const SunShaderMaterial = shaderMaterial(
  { 
    uTime: 0, 
    uColorPrimary: new Color('#FFD700'),   // SDO Gold
    uColorSecondary: new Color('#8B0000'), // Deep Red/Brown for depth
    uColorBright: new Color('#FFFFE0')     // Hot white highlights
  },
  // Vertex Shader
  `
    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vViewPosition;

    void main() {
      vUv = uv;
      vNormal = normalize(normalMatrix * normal);
      vPosition = position;

      vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
      vViewPosition = -mvPosition.xyz;

      gl_Position = projectionMatrix * mvPosition;
    }
  `,
  // Fragment Shader
  `
    uniform float uTime;
    uniform vec3 uColorPrimary;
    uniform vec3 uColorSecondary;
    uniform vec3 uColorBright;

    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vViewPosition;

    // --- Ashima 3D Simplex Noise ---
    vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
    vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

    float snoise(vec3 v) { 
      const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
      const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);

      // First corner
      vec3 i  = floor(v + dot(v, C.yyy) );
      vec3 x0 = v - i + dot(i, C.xxx) ;

      // Other corners
      vec3 g = step(x0.yzx, x0.xyz);
      vec3 l = 1.0 - g;
      vec3 i1 = min( g.xyz, l.zxy );
      vec3 i2 = max( g.xyz, l.zxy );

      vec3 x1 = x0 - i1 + C.xxx;
      vec3 x2 = x0 - i2 + C.yyy; 
      vec3 x3 = x0 - D.yyy;      

      // Permutations
      i = mod289(i); 
      vec4 p = permute( permute( permute( 
                 i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
               + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
               + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

      float n_ = 0.142857142857; 
      vec3  ns = n_ * D.wyz - D.xzx;

      vec4 j = p - 49.0 * floor(p * ns.z * ns.z); 

      vec4 x_ = floor(j * ns.z);
      vec4 y_ = floor(j - 7.0 * x_ );    

      vec4 x = x_ *ns.x + ns.yyyy;
      vec4 y = y_ *ns.x + ns.yyyy;
      vec4 h = 1.0 - abs(x) - abs(y);

      vec4 b0 = vec4( x.xy, y.xy );
      vec4 b1 = vec4( x.zw, y.zw );

      vec4 s0 = floor(b0)*2.0 + 1.0;
      vec4 s1 = floor(b1)*2.0 + 1.0;
      vec4 sh = -step(h, vec4(0.0));

      vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
      vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

      vec3 p0 = vec3(a0.xy,h.x);
      vec3 p1 = vec3(a0.zw,h.y);
      vec3 p2 = vec3(a1.xy,h.z);
      vec3 p3 = vec3(a1.zw,h.w);

      vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
      p0 *= norm.x;
      p1 *= norm.y;
      p2 *= norm.z;
      p3 *= norm.w;

      vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
      m = m * m;
      return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                    dot(p2,x2), dot(p3,x3) ) );
    }

    void main() {
      // 1. Dynamic Noise Surface (Boiling Plasma)
      // Use vertex position for 3D noise + Time for animation
      float noiseScale = 3.0;
      float timeScale = 0.2;
      float noiseVal = snoise(vPosition * noiseScale + vec3(uTime * timeScale));

      // Layer a second octave for detail
      float noiseVal2 = snoise(vPosition * (noiseScale * 2.0) - vec3(uTime * timeScale * 1.5));
      float combinedNoise = noiseVal * 0.6 + noiseVal2 * 0.4; // Range approx -1 to 1

      // 2. Mix Colors based on Noise
      // Remap noise to 0-1
      float t = combinedNoise * 0.5 + 0.5;

      // Mix: Dark base -> Primary Gold -> Bright Hot Spots
      vec3 base = mix(uColorSecondary, uColorPrimary, t);
      vec3 surfaceColor = mix(base, uColorBright, smoothstep(0.6, 1.0, t));

      // 3. Limb Darkening (Fresnel Effect)
      // Real sun is darker at edges (optical depth)
      vec3 viewDir = normalize(vViewPosition);
      float fresnel = dot(vNormal, viewDir); // 1.0 at center, 0.0 at edge

      // Adjust darkening curve
      float darkening = pow(fresnel, 0.6); 

      // Edges get redder/darker
      vec3 finalColor = surfaceColor * darkening;

      // Add a slight rim glow boost right at the very edge to separate from background
      float rim = 1.0 - fresnel;
      finalColor += uColorPrimary * pow(rim, 4.0) * 0.5;

      gl_FragColor = vec4(finalColor, 1.0);
    }
  `
);

// Register the shader material with R3F
extend({ SunShaderMaterial });

// Consistent TechLabel style (growing upwards)
const TechLabel: React.FC<{ name: string; color: string }> = ({ name, color }) => {
  return (
    <div className="absolute bottom-0 left-1/2 -translate-x-1/2 flex flex-col items-center pb-1 pointer-events-none select-none">
       <div 
         className="backdrop-blur-md bg-black/70 border px-3 py-1 rounded shadow-[0_0_15px_rgba(0,0,0,0.5)] transform transition-all animate-fade-in-up flex items-center gap-2 mb-[-1px]"
         style={{ borderColor: `${color}80`, boxShadow: `0 0 10px ${color}30` }}
       >
          <div className="w-1.5 h-1.5 rounded-full animate-pulse" style={{ backgroundColor: color }}></div>
          <span className="text-white font-mono font-bold tracking-widest text-xs uppercase" style={{ textShadow: `0 0 5px ${color}` }}>
            {name}
          </span>
       </div>
       <div 
         className="w-px h-12 bg-gradient-to-b from-white/50 to-transparent"
         style={{ background: `linear-gradient(to bottom, ${color}, transparent)` }}
       ></div>
    </div>
  );
};

export const Sun: React.FC<SunProps> = ({ onSelect, isSelected, isPaused, simulationSpeed }) => {
  const meshRef = useRef<Mesh>(null);
  const materialRef = useRef<ShaderMaterial>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  // Generate Corona Glow Texture (Billboard)
  const glowUrl = useMemo(() => generateSunGlowTexture(), []);
  const glowTexture = useMemo(() => new TextureLoader().load(glowUrl), [glowUrl]);

  useFrame((state, delta) => {
    if (meshRef.current && !isPaused) {
      // Rotation (Sun rotates differentially, but mesh rotation is fine for simple view)
      meshRef.current.rotation.y += delta * 0.01 * simulationSpeed;
    }

    // Animate Shader
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime * simulationSpeed;
    }
  });

  return (
    <group>
      {/* Main Dynamic Sun Body */}
      <mesh 
        ref={meshRef}
        onPointerDown={(e) => { e.stopPropagation(); clickStartRef.current = { x: e.clientX, y: e.clientY }; }}
        onClick={(e) => {
          e.stopPropagation();
          const dx = e.clientX - clickStartRef.current.x;
          const dy = e.clientY - clickStartRef.current.y;
          if (Math.sqrt(dx * dx + dy * dy) < 5) onSelect(SUN_DATA.id);
        }}
        onPointerOver={() => { document.body.style.cursor = 'pointer'; setHovered(true); }}
        onPointerOut={() => { document.body.style.cursor = 'auto'; setHovered(false); }}
      >
        <sphereGeometry args={[SUN_DATA.size, 128, 128]} /> {/* Increased segments for smoother shader noise */}

        {/* Use the Custom Shader */}
        {/* @ts-ignore */}
        <sunShaderMaterial 
           ref={materialRef}
           uColorPrimary={new Color('#FFD700')}   // SDO 171 Gold
           uColorSecondary={new Color('#8B0000')} // Deep Red
           uColorBright={new Color('#FFFFE0')}    // White Hot
        />

        {/* Tech Style Hover Label (Upwards) */}
        {hovered && (
          <Html position={[0, SUN_DATA.size, 0]} zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
             <TechLabel name={SUN_DATA.name} color="#FFD700" />
          </Html>
        )}
      </mesh>

      {/* Inner Glow Layer - Golden White */}
      <Billboard>
         <mesh position={[0, 0, -0.1]}>
            <planeGeometry args={[SUN_DATA.size * 2.8, SUN_DATA.size * 2.8]} />
            <meshBasicMaterial map={glowTexture} transparent opacity={0.5} depthWrite={false} blending={AdditiveBlending} color="#FFD700" />
         </mesh>
      </Billboard>

      {/* Outer Glow Layer - Orange Corona */}
       <Billboard>
         <mesh position={[0, 0, -0.2]}>
            <planeGeometry args={[SUN_DATA.size * 5.5, SUN_DATA.size * 5.5]} />
            <meshBasicMaterial map={glowTexture} transparent opacity={0.3} depthWrite={false} blending={AdditiveBlending} color="#FF4500" />
         </mesh>
       </Billboard>
    </group>
  );
};

