export const Sun: React.FC<SunProps> = ({ onSelect, isSelected, isPaused, simulationSpeed }) => {
  const meshRef = useRef<Mesh>(null);
  const materialRef = useRef<ShaderMaterial>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  // Generate Corona Glow Texture (Billboard)
  const glowUrl = useMemo(() => generateSunGlowTexture(), []);
  const glowTexture = useMemo(() => new TextureLoader().load(glowUrl), [glowUrl]);

  useFrame((state, delta) => {
    if (meshRef.current && !isPaused) {
      // Rotation (Sun rotates differentially, but mesh rotation is fine for simple view)
      meshRef.current.rotation.y += delta * 0.01 * simulationSpeed;
    }

    // Animate Shader
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime * simulationSpeed;
    }
  });

  return (
    <group>
      {/* Main Dynamic Sun Body */}
      <mesh 
        ref={meshRef}
        onPointerDown={(e) => { e.stopPropagation(); clickStartRef.current = { x: e.clientX, y: e.clientY }; }}
        onClick={(e) => {
          e.stopPropagation();
          const dx = e.clientX - clickStartRef.current.x;
          const dy = e.clientY - clickStartRef.current.y;
          if (Math.sqrt(dx * dx + dy * dy) < 5) onSelect(SUN_DATA.id);
        }}
        onPointerOver={() => { document.body.style.cursor = 'pointer'; setHovered(true); }}
        onPointerOut={() => { document.body.style.cursor = 'auto'; setHovered(false); }}
      >
        <sphereGeometry args={[SUN_DATA.size, 128, 128]} /> {/* High segments for smooth shader */}

        {/* Use the Custom Shader with Solar Max Colors */}
        {/* @ts-ignore */}
        <sunShaderMaterial 
           ref={materialRef}
           uColorPrimary={new Color('#FFD700')}   // Bright Gold
           uColorSecondary={new Color('#CD5C5C')} // Cooler Indian Red
           uColorSunspot={new Color('#200500')}   // Umbra (Deep Black/Brown)
           uColorPenumbra={new Color('#8B3A00')}  // Penumbra (Rusty)
           uColorBright={new Color('#FFFFFF')}    // Flare White
        />

        {/* Tech Style Hover Label (Upwards) */}
        {hovered && (
          <Html position={[0, SUN_DATA.size, 0]} zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
             <TechLabel name={SUN_DATA.name} color="#FFD700" />
          </Html>
        )}
      </mesh>

      {/* Inner Glow Layer - Golden White */}
      <Billboard>
         <mesh position={[0, 0, -0.1]}>
            <planeGeometry args={[SUN_DATA.size * 2.8, SUN_DATA.size * 2.8]} />
            <meshBasicMaterial map={glowTexture} transparent opacity={0.5} depthWrite={false} blending={AdditiveBlending} color="#FFD700" />
         </mesh>
      </Billboard>

      {/* Outer Glow Layer - Orange Corona */}
       <Billboard>
         <mesh position={[0, 0, -0.2]}>
            <planeGeometry args={[SUN_DATA.size * 5.5, SUN_DATA.size * 5.5]} />
            <meshBasicMaterial map={glowTexture} transparent opacity={0.3} depthWrite={false} blending={AdditiveBlending} color="#FF4500" />
         </mesh>
       </Billboard>
    </group>
  );
};

